#pragma mark - Game Logic

- (void)resetGame {
    self.isPlayerXTurn = YES;
    self.movesCount = 0;
    self.gameEnded = NO;
    self.moveHistory = [NSMutableArray array];

    // Update player indicator
    [self updatePlayerIndicators];

    for (UIButton *button in self.boardButtons) {
        [button setTitle:@"" forState:UIControlStateNormal];
        button.titleLabel.hidden = YES;
        [button setImage:nil forState:UIControlStateNormal];
        button.enabled = YES;
        button.backgroundColor = [UIColor clearColor];
    }

    // Update undo button state
    self.undoButton.enabled = NO;
    self.undoButton.alpha = 0.5;
}

- (void)updatePlayerIndicators {
    if (self.isPlayerXTurn) {
        _playerIndicator.selectedSegmentIndex = 0;
        } else {
        _playerIndicator.selectedSegmentIndex = 1;
        }
}

- (void)boardButtonTapped:(UIButton *)sender {
    if (self.gameEnded) {
        return;
    }

    NSString *symbol = self.isPlayerXTurn ? @"X" : @"O";
    UIImage *icon = [UIImage imageNamed: self.isPlayerXTurn ? @"A_X" : @"A_O"];
    [sender setImage:icon forState:UIControlStateNormal];
    [sender setTitle:symbol forState:UIControlStateNormal];
    sender.titleLabel.hidden = YES;
    [sender setTitleColor:self.isPlayerXTurn ? [UIColor redColor] : [UIColor blueColor] forState:UIControlStateNormal];
    sender.enabled = NO;

    // Record this move
    [self.moveHistory addObject:@{
        @"tag": @(sender.tag),
        @"symbol": symbol
    }];

    // Update undo button state
    self.undoButton.enabled = YES;
    self.undoButton.alpha = 1.0;

    // Check win condition
    if ([self checkForWinner]) {
        self.gameEnded = YES;
        [self showAlertWithWinner:[NSString stringWithFormat:@"%@",self.isPlayerXTurn ? @"X" : @"O"]];
    }

    self.movesCount++;
    if (self.movesCount >= 9) {
        self.gameEnded = YES;
        [self showAlertWithWinner:@"Draw"];
    }

    // Switch player
    self.isPlayerXTurn = !self.isPlayerXTurn;
    [self updatePlayerIndicators];
}

- (void)undoMove {
    if (self.gameEnded || self.moveHistory.count == 0) {
        return;
    }

    // Get last move
    NSDictionary *lastMove = [self.moveHistory lastObject];
    NSInteger tag = [lastMove[@"tag"] integerValue];
    NSString *symbol = lastMove[@"symbol"];

    // Restore button state
    UIButton *button = self.boardButtons[tag];
    [button setTitle:@"" forState:UIControlStateNormal];
    button.titleLabel.hidden = YES;
    [button setImage:nil forState:UIControlStateNormal];
    button.enabled = YES;
    button.backgroundColor = [UIColor clearColor];

    // Remove from history
    [self.moveHistory removeLastObject];

    // Update game state
    self.movesCount--;
    self.isPlayerXTurn = [symbol isEqualToString:@"X"];
    [self updatePlayerIndicators];

    // Update undo button state
    if (self.moveHistory.count == 0) {
        self.undoButton.enabled = NO;
        self.undoButton.alpha = 0.5;
    }
}

- (void)showAlertWithWinner:(NSString *)winner {
    NSString *message;
    UIImage *winnerImage;
    if ([winner isEqualToString:@"Draw"]) {
        message = @"Draw";
    } else if([winner isEqualToString:@"X"]) {
        message = @"Winner";
        winnerImage = [UIImage imageNamed:@"A_X"];
    } else {
        message = @"Winner";
        winnerImage = [UIImage imageNamed:@"A_O"];
    }

    UIAlertController *alert = [UIAlertController alertControllerWithTitle:@"Game Over"
                                                                   message:message
                                                                   message:message
                                                            preferredStyle:UIAlertControllerStyleAlert];

    UIImageView *imageView = [[UIImageView alloc] initWithImage:winnerImage];
    imageView.contentMode = UIViewContentModeScaleAspectFit;
    imageView.frame = CGRectMake(ZOOM(90), ZOOM(35), ZOOM(20), ZOOM(20));

    // Add image view to alert
    [alert.view addSubview:imageView];

    [alert addAction:[UIAlertAction actionWithTitle:@"Restart"
                                              style:UIAlertActionStyleDefault
                                            handler:^(UIAlertAction * _Nonnull action) {
        [self resetGame];
        return;
    }]];

    [alert addAction:[UIAlertAction actionWithTitle:@"Confirm"
                                              style:UIAlertActionStyleCancel
                                            handler:^(UIAlertAction * _Nonnull action){return;}]];
    [self presentViewController:alert animated:YES completion:nil];
}

- (BOOL)checkForWinner {
    // Check rows
    for (int row = 0; row < 3; row++) {
        if ([self compareButtonAtRow:row col:0 withRow:row col:1 andRow:row col:2]) {
            return YES;
        }
    }

    // Check columns
    for (int col = 0; col < 3; col++) {
        if ([self compareButtonAtRow:0 col:col withRow:1 col:col andRow:2 col:col]) {
            return YES;
        }
    }

    // Check diagonals
    if ([self compareButtonAtRow:0 col:0 withRow:1 col:1 andRow:2 col:2]) {
        return YES;
    }

    if ([self compareButtonAtRow:0 col:2 withRow:1 col:1 andRow:2 col:0]) {
        return YES;
    }

    return NO;
}

- (BOOL)compareButtonAtRow:(NSInteger)row1 col:(NSInteger)col1
                   withRow:(NSInteger)row2 col:(NSInteger)col2
                   andRow:(NSInteger)row3 col:(NSInteger)col3 {
    NSInteger index1 = row1 * 3 + col1;
    NSInteger index2 = row2 * 3 + col2;
    NSInteger index3 = row3 * 3 + col3;

    UIButton *button1 = self.boardButtons[index1];
    UIButton *button2 = self.boardButtons[index2];
    UIButton *button3 = self.boardButtons[index3];

    NSString *text1 = [button1 currentTitle];
    NSString *text2 = [button2 currentTitle];
    NSString *text3 = [button3 currentTitle];

    if (![text1 isEqualToString:@""] && [text1 isEqualToString:text2] && [text1 isEqualToString:text3]) {
        return YES;
    }

    return NO;
}

