        UIImage *oImage = [self resizeImage:[UIImage imageNamed:@"A_O"] toSize:CGSizeMake(ZOOM(20), ZOOM(20))];
        _playerIndicator = [[UISegmentedControl alloc] initWithItems:@[xImage, oImage]];
        _playerIndicator.selectedSegmentIndex = 0;
        _playerIndicator.backgroundColor = RGBA(213, 223, 225, 1);
        _playerIndicator.enabled = NO;
    }
    return _playerIndicator;
}

- (UILabel *)titleLabel {
    if (!_titleLabel) {
        _titleLabel = [[UILabel alloc] init];
        _titleLabel.font = [UIFont systemFontOfSize:32 weight:UIFontWeightBold];
        _titleLabel.textColor = [UIColor darkGrayColor];
    }
    return _titleLabel;
}

- (UIImageView *)backGround {
    if (!_backGround) {
        _backGround = [[UIImageView alloc] initWithImage:[UIImage imageNamed:@"A_boardimage"]];
    }
    return _backGround;
}

- (UIView *)gameBoard {
    if (!_gameBoard) {
        _gameBoard = [[UIView alloc] init];
        _gameBoard.backgroundColor = [UIColor clearColor];
    }
    return _gameBoard;
}

- (UIButton *)resetButton {
    if (!_resetButton) {
        _resetButton = [UIButton buttonWithType:UIButtonTypeSystem];
//        [_resetButton setBackgroundImage:[UIImage imageNamed:@"A_reset"] forState:UIControlStateNormal];
        [_resetButton setTitle:@"Restart" forState:UIControlStateNormal];
        [_resetButton setTitleColor:WHITE_COLOR forState:UIControlStateNormal];
        [_resetButton setBackgroundColor:DEEP_COLOR];
        _resetButton.layer.cornerRadius = ZOOM(12);
        [_resetButton addTarget:self action:@selector(resetGame) forControlEvents:UIControlEventTouchUpInside];
    }
    return _resetButton;
}

- (UIButton *)undoButton {
    if (!_undoButton) {
        _undoButton = [UIButton buttonWithType:UIButtonTypeSystem];
        [_undoButton setTitle:@"Revoke" forState:UIControlStateNormal];
        [_undoButton setTitleColor:DEEP_COLOR forState:UIControlStateNormal];
        [_undoButton setBackgroundColor:WHITE_COLOR];
        _undoButton.layer.borderColor = DEEP_COLOR.CGColor;
        _undoButton.layer.borderWidth = ZOOM(1);
        _undoButton.layer.cornerRadius = ZOOM(12);
        [_undoButton addTarget:self action:@selector(undoMove) forControlEvents:UIControlEventTouchUpInside];
        _undoButton.enabled = NO;
        _undoButton.alpha = 0.5;
    }
    return _undoButton;
}

- (UIImage *)resizeImage:(UIImage *)image toSize:(CGSize)targetSize {
    UIGraphicsBeginImageContextWithOptions(targetSize, NO, 0.0);
    [image drawInRect:CGRectMake(0, 0, targetSize.width, targetSize.height)];
    UIImage *newImage = UIGraphicsGetImageFromCurrentImageContext();
    UIGraphicsEndImageContext();
    return newImage;
}

